import React, { useState, useEffect } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import HeartModel from './HeartModel';
import PhotoStars from './PhotoStar';
import GalaxyBackground from './GalaxyBackground';

// ===================================================
// 🎨 KUSTOMISASI — Edit bagian ini sesuai keinginan!
// ===================================================

const NAMA_PACAR = "Sayang"; // Ganti nama pacar kamu

const PESAN_ROMANTIS = [
  "Setiap momen bersamamu adalah hadiah terindah 💕",
  "Kamu adalah cahaya dalam hidupku ✨",
  "Terima kasih sudah hadir di hidupku 🌹",
  "Happy Birthday, semoga semua impianmu terwujud 🎂",
];

// Foto-foto kenangan — taruh file foto kamu di folder /public/photos/
// lalu isi nama filenya di sini (misalnya "foto1.jpg", "foto2.jpg", dll.)
// Jika belum punya foto, biarkan array ini kosong [] dan placeholder warna akan muncul
const FOTO_KENANGAN = [
  // "/photos/foto1.jpg",
  // "/photos/foto2.jpg",
  // "/photos/foto3.jpg",
  // dst...
];

// Jika array foto kosong, gunakan placeholder warna-warni
const PLACEHOLDER_COLORS = [
  "#ff6b9d","#c44dff","#4d79ff","#ff4d6b","#ff9f43",
  "#54a0ff","#ff6348","#ffd32a","#0be881","#f368e0",
  "#ff9ff3","#48dbfb","#1dd1a1","#ffeaa7","#dfe6e9",
  "#fd79a8","#a29bfe","#74b9ff","#fab1a0","#55efc4",
  "#e17055","#00cec9","#fdcb6e","#6c5ce7","#00b894",
  "#d63031","#0984e3","#e84393","#636e72","#b2bec3",
  "#ff7675","#81ecec","#778ca3","#fdfd96","#c7ecee",
  "#a55eea","#f7b731","#fc5c65","#45aaf2","#26de81",
  "#fd9644","#2bcbba","#eb3b5a","#3867d6","#20bf6b",
  "#ff85c1","#7bed9f","#eccc68","#70a1ff","#ff6b81",
];

const photoList = FOTO_KENANGAN.length > 0
  ? FOTO_KENANGAN
  : PLACEHOLDER_COLORS.map((c, i) => `__color__${c}`);

// ===================================================

const css = `
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;1,400&family=Lato:wght@300;400&display=swap');

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(-10px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes fadeInScale {
  from { opacity: 0; transform: scale(0.8); }
  to { opacity: 1; transform: scale(1); }
}
@keyframes slideUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes rotateSlow {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}
.close-btn:hover {
  background: rgba(255,255,255,0.2) !important;
  transform: scale(1.1);
}
.mute-btn:hover {
  background: rgba(255,130,180,0.25) !important;
}
`;

export default function GalaxyScene() {
  const [selectedPhoto, setSelectedPhoto] = useState(null);
  const [msgIndex, setMsgIndex] = useState(0);
  const [muted, setMuted] = useState(true);
  const [showHint, setShowHint] = useState(true);

  // Cycle through messages
  useEffect(() => {
    const interval = setInterval(() => {
      setMsgIndex(i => (i + 1) % PESAN_ROMANTIS.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  // Hide hint after 5 seconds
  useEffect(() => {
    const t = setTimeout(() => setShowHint(false), 5000);
    return () => clearTimeout(t);
  }, []);

  const handlePhotoClick = (photo, index) => {
    setSelectedPhoto(photo);
  };

  const closePhoto = () => setSelectedPhoto(null);

  const isColorPlaceholder = (photo) => photo && photo.startsWith('__color__');
  const getColor = (photo) => photo && photo.replace('__color__', '');

  return (
    <>
      <style>{css}</style>

      {/* 3D Canvas */}
      <Canvas
        camera={{ position: [0, 2, 22], fov: 65 }}
        style={{ width: '100vw', height: '100vh', background: '#000' }}
        gl={{ antialias: true, alpha: false }}
      >
        {/* Lighting */}
        <ambientLight intensity={0.3} color="#ffffff" />
        <directionalLight position={[5, 5, 5]} intensity={0.8} color="#ffccee" />
        <directionalLight position={[-5, -3, -3]} intensity={0.3} color="#aabbff" />

        {/* Galaxy Stars */}
        <GalaxyBackground />

        {/* Heart */}
        <HeartModel />

        {/* Photo Stars */}
        <PhotoStars
          photos={photoList}
          onPhotoClick={handlePhotoClick}
        />

        {/* Camera Controls */}
        <OrbitControls
          enablePan={false}
          minDistance={5}
          maxDistance={35}
          autoRotate
          autoRotateSpeed={0.4}
          makeDefault
        />
      </Canvas>

      {/* UI Overlay */}

      {/* Top title */}
      <div style={{
        position: 'fixed', top: 0, left: 0, right: 0,
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        padding: '2rem 1rem 1rem',
        background: 'linear-gradient(to bottom, rgba(0,0,0,0.7) 0%, transparent 100%)',
        pointerEvents: 'none',
        animation: 'fadeIn 1.5s ease forwards',
      }}>
        <h1 style={{
          fontFamily: "'Playfair Display', serif",
          fontStyle: 'italic',
          fontSize: 'clamp(1.2rem, 4vw, 2.2rem)',
          color: '#fff',
          textShadow: '0 0 30px rgba(255,130,180,0.9)',
          textAlign: 'center',
          marginBottom: '0.3rem',
        }}>
          Happy Birthday, {NAMA_PACAR}! 🎂
        </h1>
      </div>

      {/* Bottom message */}
      <div style={{
        position: 'fixed', bottom: 0, left: 0, right: 0,
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        padding: '1rem 1rem 2.5rem',
        background: 'linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 100%)',
        pointerEvents: 'none',
      }}>
        <p key={msgIndex} style={{
          fontFamily: "'Playfair Display', serif",
          fontStyle: 'italic',
          fontSize: 'clamp(0.9rem, 2.5vw, 1.3rem)',
          color: 'rgba(255,200,230,0.95)',
          textAlign: 'center',
          animation: 'slideUp 0.8s ease forwards',
          textShadow: '0 0 20px rgba(255,100,150,0.6)',
          maxWidth: '600px',
          padding: '0 1rem',
        }}>
          {PESAN_ROMANTIS[msgIndex]}
        </p>

        {showHint && (
          <p style={{
            fontFamily: "'Lato', sans-serif",
            fontWeight: 300,
            fontSize: '0.75rem',
            color: 'rgba(255,200,230,0.5)',
            textAlign: 'center',
            marginTop: '0.6rem',
            letterSpacing: '0.1em',
            animation: 'fadeIn 1s ease 1s both',
          }}>
            💫 Klik foto untuk memperbesar · Drag untuk memutar · Scroll untuk zoom
          </p>
        )}
      </div>

      {/* Mute/Unmute button */}
      <button
        className="mute-btn"
        onClick={() => setMuted(!muted)}
        style={{
          position: 'fixed',
          bottom: '1.5rem',
          right: '1.5rem',
          background: 'rgba(255,130,180,0.12)',
          border: '1px solid rgba(255,130,180,0.3)',
          color: 'rgba(255,200,230,0.8)',
          borderRadius: '50%',
          width: '44px',
          height: '44px',
          fontSize: '1.2rem',
          cursor: 'pointer',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          transition: 'all 0.3s ease',
          backdropFilter: 'blur(10px)',
          zIndex: 50,
        }}
        title={muted ? 'Putar Musik' : 'Matikan Musik'}
      >
        {muted ? '🔇' : '🎵'}
      </button>

      {/* Photo zoom overlay */}
      {selectedPhoto && (
        <div
          onClick={closePhoto}
          style={{
            position: 'fixed', inset: 0,
            background: 'rgba(0,0,0,0.85)',
            zIndex: 200,
            backdropFilter: 'blur(8px)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}
        >
          <div
            onClick={e => e.stopPropagation()}
            style={{
              position: 'relative',
              animation: 'fadeInScale 0.4s cubic-bezier(0.34,1.56,0.64,1) forwards',
              width: 'min(80vw, 720px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            {isColorPlaceholder(selectedPhoto) ? (
              <div style={{
                width: '100%',
                aspectRatio: '4/3',
                background: `radial-gradient(circle at 30% 30%, white 0%, ${getColor(selectedPhoto)} 60%)`,
                borderRadius: '20px',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: '6rem',
                boxShadow: `0 0 80px ${getColor(selectedPhoto)}99, 0 0 160px ${getColor(selectedPhoto)}44`,
              }}>
                💕
              </div>
            ) : (
              <img
                src={selectedPhoto}
                alt="Kenangan"
                style={{
                  width: '100%',
                  maxHeight: '80vh',
                  borderRadius: '20px',
                  boxShadow: '0 0 80px rgba(255,130,180,0.6), 0 0 160px rgba(255,80,150,0.25)',
                  display: 'block',
                  objectFit: 'contain',
                }}
              />
            )}

            {/* Close button */}
            <button
              className="close-btn"
              onClick={closePhoto}
              style={{
                position: 'absolute',
                top: '-18px',
                right: '-18px',
                background: 'rgba(0,0,0,0.6)',
                border: '1px solid rgba(255,255,255,0.35)',
                color: '#fff',
                borderRadius: '50%',
                width: '44px',
                height: '44px',
                fontSize: '1.1rem',
                cursor: 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                transition: 'all 0.2s ease',
                backdropFilter: 'blur(12px)',
                zIndex: 10,
              }}
            >
              ✕
            </button>
          </div>

          {/* Click outside to close hint */}
          <p style={{
            position: 'absolute',
            bottom: '2rem',
            left: '50%',
            transform: 'translateX(-50%)',
            fontFamily: "'Lato', sans-serif",
            fontWeight: 300,
            fontSize: '0.8rem',
            color: 'rgba(255,255,255,0.4)',
            letterSpacing: '0.1em',
          }}>
            Klik di luar foto untuk menutup
          </p>
        </div>
      )}
    </>
  );
}
